import java.util.Scanner;

public class ScanAltura {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

	
	
		Scanner scan = new Scanner(System.in);
		
		 
		System.out.println("Insira a primeira altura: ");
		double altura1 = scan.nextDouble();
		
		System.out.println("Insira a segunda altura: ");
		double altura2 = scan.nextDouble();
		
		 double diferencaAltura = altura1 - altura2; 
		
		System.out.println("A diferença de altura entre as duas pessoas é: "+diferencaAltura+"cm");
		
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	}

}
